from typing import Optional, List, Dict

# 假设用户类型为 dict
User = Dict[str, object]

# 全局缓存（或使用类封装）
_user_cache: Optional[Dict[int, User]] = None

def load_users() -> List[User]:
    """从数据源加载用户列表"""
    # 实际加载逻辑...
